static constexpr uint32_t MAX_BLOCK_DIM = 24;

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    VanillaRnnHiddenCustomTilingData tiling;
    const auto x_shape = context->GetInputShape(0)->GetOriginShape();
    const uint32_t T = static_cast<uint32_t>(x_shape.GetDim(0));
    const uint32_t B = static_cast<uint32_t>(x_shape.GetDim(1));
    const uint32_t I = static_cast<uint32_t>(x_shape.GetDim(2));
    const auto h0_shape = context->GetInputShape(1)->GetOriginShape();
    const uint32_t H = static_cast<uint32_t>(h0_shape.GetDim(1));
    const auto w_h2o_shape = context->GetInputShape(4)->GetOriginShape();
    const uint32_t O = static_cast<uint32_t>(w_h2o_shape.GetDim(0));
    const uint32_t K = I + H;

    uint32_t blockDim = (B < MAX_BLOCK_DIM) ? B : MAX_BLOCK_DIM;
    context->SetBlockDim(blockDim);

    tiling.set_T(T);
    tiling.set_B(B);
    tiling.set_I(I);
    tiling.set_H(H);
    tiling.set_O(O);
    tiling.set_K(K);
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

} // namespace optiling

